public static str getDimValue(LedgerDefaultDimensionValueSet ledgerDimensionAccount, Name dimName)
{
    DimensionAttributeLevelValueAllView  dimAttrView;
    DimensionAttribute dimAttr;
    str dimvalue;
    select DisplayValue from dimAttrView where dimattrview.ValueCombinationRecId == ledgerDimensionAccount
              join BackingEntityType from dimAttr
            where dimAttr.RecId == dimAttrView.DimensionAttribute
        && dimAttr.Name == dimName;
    if(dimAttrView.DisplayValue)
    {
        dimvalue = dimAttrView.DisplayValue;
    }
    return dimvalue;
}

public static DimensionDisplayValue getAttributeValueFromCombination(RecId _ledgerDimension ,    Name _dimName)
    {
        DimensionAttributeLevelValueView valueView;
        DimensionAttribute attribute = DimensionAttribute::findByName(_dimName); //Retrive attribute record by Name

        select valueView
where valueView.ValueCombinationRecId == _ledgerDimension
&& valueView.DimensionAttribute == attribute.RecId; //Retrieve individual Dimension attribute record

        return valueView.DisplayValue; //Retrive dimension attribute value
    }
